#!/usr/bin/env bash
# E2E Test: Verify all JSON responses use consistent envelope format
set -euo pipefail

LOG_FILE="/tmp/rch_e2e_api_envelope_$(date +%Y%m%d_%H%M%S).log"
FAILED=0

log() {
    local level="$1"; shift
    local ts=$(date -Iseconds)
    echo "[$ts] [$level] $*" | tee -a "$LOG_FILE"
}

check_envelope() {
    local cmd_name="$1"
    local json="$2"

    log "TEST" "Checking envelope for: $cmd_name"

    # Required fields
    for field in api_version timestamp success; do
        if ! echo "$json" | jq -e ".$field" > /dev/null 2>&1; then
            log "FAIL" "$cmd_name: Missing required field '$field'"
            log "DEBUG" "Response: $json"
            FAILED=$((FAILED + 1))
            return 1
        fi
    done

    # api_version should be "1.0"
    local version=$(echo "$json" | jq -r '.api_version')
    if [ "$version" != "1.0" ]; then
        log "FAIL" "$cmd_name: Expected api_version '1.0', got '$version'"
        FAILED=$((FAILED + 1))
        return 1
    fi

    # timestamp should be reasonable (within last hour)
    local ts=$(echo "$json" | jq -r '.timestamp')
    local now=$(date +%s)
    local diff=$((now - ts))
    if [ $diff -gt 3600 ] || [ $diff -lt -60 ]; then
        log "WARN" "$cmd_name: Timestamp looks wrong (diff: ${diff}s)"
    fi

    # success field should be boolean
    local success=$(echo "$json" | jq -r '.success')
    if [ "$success" != "true" ] && [ "$success" != "false" ]; then
        log "FAIL" "$cmd_name: 'success' should be boolean, got '$success'"
        FAILED=$((FAILED + 1))
        return 1
    fi

    log "PASS" "$cmd_name: Envelope format correct"
    return 0
}

log "INFO" "Starting API envelope E2E tests"
log "INFO" "Log file: $LOG_FILE"

# Build
cargo build -p rch --release 2>&1 | tee -a "$LOG_FILE"
RCH="./target/release/rch"

# Test various commands
log "INFO" "Testing CLI commands..."

# rch status --json
log "TEST" "rch status --json"
OUTPUT=$($RCH status --json 2>&1 || true)
check_envelope "rch status" "$OUTPUT"

# rch workers list --json
log "TEST" "rch workers list --json"  
OUTPUT=$($RCH workers list --json 2>&1 || true)
check_envelope "rch workers list" "$OUTPUT"

# rch config show --json
log "TEST" "rch config show --json"
OUTPUT=$($RCH config show --json 2>&1 || true)
check_envelope "rch config show" "$OUTPUT"

# rch doctor --json
log "TEST" "rch doctor --json"
OUTPUT=$($RCH doctor --json 2>&1 || true)
check_envelope "rch doctor" "$OUTPUT"

# Error case: invalid worker
log "TEST" "Error response envelope"
OUTPUT=$($RCH workers probe nonexistent --json 2>&1 || true)
check_envelope "workers probe (error)" "$OUTPUT"

# Verify error has proper structure
if echo "$OUTPUT" | jq -e '.error.code' > /dev/null 2>&1; then
    log "PASS" "Error response includes error object with code"
else
    log "FAIL" "Error response missing error.code"
    FAILED=$((FAILED + 1))
fi

# Summary
log "INFO" "========================================"
if [ $FAILED -eq 0 ]; then
    log "INFO" "ALL TESTS PASSED"
    exit 0
else
    log "ERROR" "$FAILED test(s) failed"
    exit 1
fi
